#!/usr/bin/env python3
import base64, ast, json, os, sys
SETUP_B64 = ""
SETTINGS_B64 = ""
here = os.path.dirname(os.path.abspath(__file__))
ok = True
try:
    p = os.path.join(here, "setup.py")
    open(p, "wb").write(base64.b64decode(SETUP_B64))
    src = open(p).read(); ast.parse(src)
    assert "seed_settings" in src
    print("[OK] setup.py (" + str(len(src)) + " bytes)")
except Exception as e:
    ok = False; print("[FAIL] setup.py: " + str(e))
try:
    p = os.path.join(here, "doctype", "logistics_settings", "logistics_settings.json")
    open(p, "wb").write(base64.b64decode(SETTINGS_B64))
    d = json.load(open(p))
    assert d.get("issingle") == 1 and "auto_create_accounting" in d.get("field_order",[])
    print("[OK] settings.json (issingle=1, auto_create_accounting)")
except Exception as e:
    ok = False; print("[FAIL] settings.json: " + str(e))
print("ALL OK" if ok else "FIX FIRST")
sys.exit(0 if ok else 1)
